Install:
uvx awslabs.core-mcp-server@latest && claude mcp list

Config:
{
  "aws": {
    "env": {
      "AWS_REGION": "${AWS_REGION:-us-east-1}",
      "AWS_PROFILE": "${AWS_PROFILE}",
      "FASTMCP_LOG_LEVEL": "${FASTMCP_LOG_LEVEL:-ERROR}"
    },
    "args": [
      "awslabs.core-mcp-server@latest"
    ],
    "command": "uvx"
  }
}

Usage:
{
  "aws": {
    "env": {
      "AWS_REGION": "${AWS_REGION:-us-east-1}",
      "AWS_PROFILE": "${AWS_PROFILE}",
      "FASTMCP_LOG_LEVEL": "${FASTMCP_LOG_LEVEL:-ERROR}"
    },
    "args": [
      "awslabs.core-mcp-server@latest"
    ],
    "command": "uvx"
  }
}
